/**
 * Look up soil data for a region.
 * Tries exact match first, then fuzzy match by district + state.
 * @param {string} district - e.g. "Nashik"
 * @param {string} state    - e.g. "Maharashtra"
 * @returns {{ soil_type, soil_ph, moisture_level, organic_carbon } | null}
 */
function getSoilData(district, state) {
  if (!district && !state) return null;

  // 1. Exact match: "District, State"
  if (district && state) {
    const key = `${district}, ${state}`;
    if (SOIL_DATA[key]) return SOIL_DATA[key];
  }

  // 2. Partial match — find any key that contains the district name
  if (district) {
    const lower = district.toLowerCase();
    const match = Object.keys(SOIL_DATA).find(k => k.toLowerCase().startsWith(lower));
    if (match) return SOIL_DATA[match];
  }

  // 3. State-level fallback — first region in that state
  if (state) {
    const lower = state.toLowerCase();
    const match = Object.keys(SOIL_DATA).find(k => k.toLowerCase().endsWith(lower));
    if (match) return SOIL_DATA[match];
  }

  return null;
}

/**
 * Generate soil health advice string for the advisor response.
 * @param {{ soil_type, soil_ph, moisture_level, organic_carbon }} soil
 * @returns {string}
 */
function getSoilHealthTip(soil) {
  const tips = [];

  // pH advice
  if (soil.soil_ph < 6.0) tips.push(`Soil is acidic (pH ${soil.soil_ph}) — consider lime application to raise pH.`);
  else if (soil.soil_ph > 7.5) tips.push(`Soil is alkaline (pH ${soil.soil_ph}) — gypsum or sulphur can help neutralise it.`);
  else tips.push(`Soil pH is optimal (${soil.soil_ph}) — good for most crops.`);

  // Moisture
  if (soil.moisture_level === 'Low') tips.push('Low soil moisture — drip irrigation or mulching recommended.');
  else if (soil.moisture_level === 'High') tips.push('High moisture retention — ensure proper drainage to avoid waterlogging.');

  // Organic carbon
  if (soil.organic_carbon === 'Low') tips.push('Low organic carbon — add compost or green manure to improve fertility.');
  else if (soil.organic_carbon === 'High') tips.push('High organic carbon — excellent soil health, maintain with crop rotation.');

  return tips.join(' ');
}

module.exports = { SOIL_DATA, getSoilData, getSoilHealthTip };
